const fs = require('fs');
const path = require('path');

const ARTIFACTS_TO_DELETE = [
  'dist', 'build', 'coverage', '.next', '.cache', 'tmp', 'temp', 'logs', 'tsc_errors.log'
];

function deleteArtifacts(basePath) {
  for (const artifact of ARTIFACTS_TO_DELETE) {
    const p = path.join(basePath, artifact);
    if (fs.existsSync(p)) {
      console.log(`Deleting artifact: ${p}`);
      fs.rmSync(p, { recursive: true, force: true });
    }
  }
}

function removeEmptyDirs(dir) {
  if (!fs.existsSync(dir)) return;
  const files = fs.readdirSync(dir);
  if (files.length === 0) {
    console.log(`Deleting empty directory: ${dir}`);
    fs.rmdirSync(dir);
    return;
  }
  for (const file of files) {
    const fullPath = path.join(dir, file);
    if (fs.statSync(fullPath).isDirectory()) {
      removeEmptyDirs(fullPath);
    }
  }
  // Check again after children are processed
  if (fs.readdirSync(dir).length === 0) {
    console.log(`Deleting empty directory: ${dir}`);
    fs.rmdirSync(dir);
  }
}

function removeZeroByteFiles(dir) {
  if (!fs.existsSync(dir)) return;
  const files = fs.readdirSync(dir);
  for (const file of files) {
    const fullPath = path.join(dir, file);
    if (fs.statSync(fullPath).isDirectory()) {
      removeZeroByteFiles(fullPath);
    } else {
      if (fs.statSync(fullPath).size === 0) {
        console.log(`Deleting zero-byte file: ${fullPath}`);
        fs.unlinkSync(fullPath);
      }
    }
  }
}

function deleteUnusedFiles(reportPath) {
  if (!fs.existsSync(reportPath)) return;
  const report = JSON.parse(fs.readFileSync(reportPath, 'utf8'));

  if (report.issues) {
    for (const issue of report.issues) {
      if (issue.files && issue.files.length > 0) {
        for (const f of issue.files) {
          const fp = path.join(process.cwd(), f.name);
          if (fs.existsSync(fp)) {
            console.log(`Deleting unused file: ${fp}`);
            fs.unlinkSync(fp);
          }
        }
      }
    }
  }
}

console.log("Starting Phase 7: Artifact Cleanup");
deleteArtifacts(process.cwd());

console.log("Starting Phase 3: Zero-byte files");
removeZeroByteFiles(path.join(process.cwd(), 'src'));

console.log("Starting Phase 2: Unused Files");
deleteUnusedFiles(path.join(process.cwd(), 'knip-report.json'));

console.log("Starting Phase 3: Empty Directories");
removeEmptyDirs(path.join(process.cwd(), 'src'));

console.log("Cleanup script finished.");

